function spanToModule(name) {
  if (SPAN_MODULE_SPECIFIC[name]) return SPAN_MODULE_SPECIFIC[name];
  for (var i = 0; i < SPAN_MODULE_PREFIX.length; i++) {
    if (name.startsWith(SPAN_MODULE_PREFIX[i][0])) return SPAN_MODULE_PREFIX[i][1];
  }
  return 'unknown';
}

